('DFAC Hours',                      'dfac-hours',          '{"blocks":[{"type":"info-cards","columns":1,"cards":[{"icon":"UtensilsCrossed","color":"amber","title":"Rocco Dining Facility","description":"Building 2846, Fort Sam Houston. Meal card required for entry. All AiT students are authorized to eat at the DFAC during posted meal times."}]},{"type":"schedule-grid","columns":[{"title":"Weekday Schedule","badge":"Mon - Fri","badgeVariant":"default","rows":[{"label":"Breakfast","value":"0600 - 0800","notes":"Hot breakfast served"},{"label":"Lunch","value":"1100 - 1300","notes":"Full lunch menu"},{"label":"Dinner","value":"1700 - 1900","notes":"Full dinner menu"},{"label":"Midnight Meal","value":"2300 - 0100","notes":"Limited menu for night shift"}]},{"title":"Weekend Schedule","badge":"Sat - Sun","badgeVariant":"secondary","rows":[{"label":"Brunch","value":"0800 - 1200","notes":"Combined breakfast/lunch menu"},{"label":"Dinner","value":"1700 - 1900","notes":"Full dinner menu"}]},{"title":"Holiday Schedule","badge":"Holidays","badgeVariant":"outline","rows":[{"label":"Brunch","value":"0900 - 1200","notes":"Special holiday brunch"},{"label":"Holiday Dinner","value":"1600 - 1900","notes":"Traditional holiday meal"}]}]},{"type":"highlight-card","icon":"AlertTriangle","title":"Hours subject to change","description":"Hours may shift for holidays, training exercises, or special events. Check with your MTL or the DFAC directly for the most current schedule.","variant":"warning"}]}'::jsonb, 'Rocco Dining Facility meal schedule and information.', 'static',  true,  15),
('Shuttle Route',                   'shuttle',             '{"blocks":[{"type":"contact-info","columns":3,"items":[{"icon":"Bus","label":"Service","value":"Base Shuttle Loop","kind":"text"},{"icon":"Clock","label":"Operating Hours","value":"Mon-Fri: 0600-2000","kind":"text","sublabel":"Sat-Sun: 0800-1800"},{"icon":"MapPin","label":"Frequency","value":"Every 30 minutes","kind":"text"}]},{"type":"numbered-steps","title":"Route Stops & Estimated Times","subtitle":"Times shown are minutes past the hour (e.g., :00 = on the hour, :30 = half past)","icon":"Bus","color":"teal","style":"dot","steps":[{"text":"METC Campus (Main Entrance)","badge":":00 / :30"},{"text":"AiT Dormitories (Building 2840)","badge":":05 / :35"},{"text":"937 TG Headquarters (Building 2841)","badge":":08 / :38"},{"text":"Rocco DFAC (Building 2846)","badge":":12 / :42"},{"text":"Jimmy Brought Fitness Center","badge":":16 / :46"},{"text":"Main Exchange (BX)","badge":":22 / :52"},{"text":"Brooke Army Medical Center (BAMC)","badge":":28 / :58"}]},{"type":"highlight-card","icon":"AlertTriangle","title":"Service may change","description":"Shuttle service may be reduced or suspended during holidays, inclement weather, or special events. Always have a backup plan for transportation to training.","variant":"warning"}]}'::jsonb, 'Base shuttle schedule and route information for JBSA-Fort Sam Houston.', 'static',  true,  16),
('Route of March',                  'route-of-march',      '{"blocks":[{"type":"numbered-steps","title":"Daily Formation Route","subtitle":"The standard route of march from the dormitories to the METC training campus.","icon":"Route","color":"military-blue","style":"numbered","steps":[{"text":"Form up at AiT Dormitories (Building 2840) parking lot"},{"text":"March south on Stanley Road"},{"text":"Turn left onto Gruber Road"},{"text":"Continue to METC Campus main entrance (Building 2841)"},{"text":"Formation dismissal at designated training building"}]},{"type":"contact-info","columns":2,"items":[{"icon":"Clock","label":"Morning Formation","value":"0720 form up / 0730 step-off","kind":"text"},{"icon":"Clock","label":"Afternoon Return","value":"1630 form up / 1640 step-off","kind":"text"}]},{"type":"checklist","icon":"Route","color":"blue","title":"Formation Guidelines","variant":"normal","items":[{"text":"Arrive at formation area 10 minutes prior to step-off time"},{"text":"Maintain proper formation alignment and cadence at all times"},{"text":"Road guards will be posted at all intersections — follow their instructions"},{"text":"No cell phones during march — stow all electronic devices"},{"text":"Carry water during warm weather months (April - October)"},{"text":"Report any injuries or issues to your element leader immediately"},{"text":"Reflective belts required during hours of limited visibility"}]}]}'::jsonb, 'Formation route details for daily marches to and from training.', 'static',  true,  17),
('Air Force Specialty Codes',       'afscs',               '{"blocks":[{"type":"info-cards","columns":1,"cards":[{"icon":"BadgeInfo","color":"blue","title":"Medical Training Programs","description":"The 937th Training Group oversees Air Force students attending medical technical training at METC. Below are the primary AFSCs trained here. Training durations are approximate and subject to change."}]},{"type":"definition-cards","columns":2,"cards":[{"badge":"4N0X1","meta":"~72 days","metaIcon":"GraduationCap","title":"Aerospace Medical Technician","description":"Provides primary and specialty healthcare at military treatment facilities. Performs patient care, emergency treatment, and health management."},{"badge":"4P0X1","meta":"~51 days","metaIcon":"GraduationCap","title":"Pharmacy Technician","description":"Prepares and dispenses medications, manages pharmacy inventory, and provides pharmaceutical care under supervision."},{"badge":"4T0X1","meta":"~72 days","metaIcon":"GraduationCap","title":"Medical Laboratory Technician","description":"Performs laboratory procedures, analyzes specimens, and provides diagnostic data for patient treatment decisions."},{"badge":"4R0X1","meta":"~52 days","metaIcon":"GraduationCap","title":"Diagnostic Imaging Technician","description":"Operates diagnostic imaging equipment to produce radiographic images for medical diagnosis and treatment."},{"badge":"4H0X1","meta":"~48 days","metaIcon":"GraduationCap","title":"Cardiopulmonary Laboratory Technician","description":"Performs diagnostic testing of the heart and lungs, including EKGs, pulmonary function tests, and cardiac monitoring."},{"badge":"4Y0X1","meta":"~35 days","metaIcon":"GraduationCap","title":"Dental Assistant","description":"Assists dental officers in treatment procedures, manages dental records, and performs dental radiology."},{"badge":"4A2X1","meta":"~92 days","metaIcon":"GraduationCap","title":"Biomedical Equipment Technician","description":"Maintains, calibrates, and repairs medical equipment used in military healthcare facilities."},{"badge":"4E0X1","meta":"~54 days","metaIcon":"GraduationCap","title":"Public Health Technician","description":"Conducts health risk assessments, disease surveillance, and environmental health inspections."}]}]}'::jsonb, 'Medical AFSCs trained at the 937th Training Group and METC.', 'static',  true,  18),
('Exceptional Family Member Program','efmp',               '{"blocks":[{"type":"info-cards","columns":1,"cards":[{"icon":"HeartHandshake","color":"pink","title":"About EFMP","description":"The Exceptional Family Member Program (EFMP) is a mandatory enrollment program that works with other military and civilian agencies to provide comprehensive and coordinated community support, housing, educational, and medical services to families with special needs."}]},{"type":"contact-info","columns":1,"items":[{"icon":"Phone","label":"EFMP Contact","value":"210-808-3700","kind":"phone"}]},{"type":"checklist","icon":"HeartHandshake","color":"pink","title":"Services Provided","variant":"normal","items":[{"text":"Identification and enrollment of family members with special needs"},{"text":"Assignment coordination to ensure medical and educational needs are met"},{"text":"Referrals to local community resources and support services"},{"text":"Assistance with Individualized Education Programs (IEPs)"},{"text":"Connection to respite care and family support programs"},{"text":"Transition assistance when PCSing to a new duty station"}]},{"type":"info-cards","heading":"Resources","columns":3,"cards":[{"icon":"Globe","color":"pink","title":"Air Force EFMP Portal","description":"Official Air Force EFMP information and resources","url":"https://www.afpc.af.mil/EFMP/"},{"icon":"Globe","color":"pink","title":"Military OneSource EFMP","description":"Comprehensive EFMP resources and support","url":"https://www.militaryonesource.mil/efmp/"},{"icon":"GraduationCap","color":"pink","title":"STOMP (Specialized Training of Military Parents)","description":"Training and support for military parents of children with special needs","url":"#"}]}]}'::jsonb, 'Support and resources for military families with special needs.',                                 'static',  true,  19),
('Airman Leadership Programs',      'leadership-programs', '{"blocks":[{"type":"info-cards","columns":1,"cards":[{"icon":"Award","color":"military-blue","title":"The Rope Program","description":"The Rope Program provides Airmen in Training with the opportunity to develop leadership skills while serving their peers. Student leaders wear colored rope aiguillettes on their uniform to signify their position. Each level carries increasing responsibility and is an excellent way to distinguish yourself during technical training."}]},{"type":"program-tiers","tiers":[{"badge":"Green Rope","color":"green","title":"Green Rope - Peer Leader","description":"The Green Rope is the entry-level student leadership position. Green Ropes serve as peer mentors and assist fellow Airmen in Training with adjusting to military life and technical training.","sections":[{"title":"Requirements","items":["Minimum 2 weeks in training","No active UIF or disciplinary actions","Maintain 80% or higher academic average","Pass most recent fitness assessment","Letter of recommendation from MTL"]},{"title":"Responsibilities","items":["Mentor newly arrived Airmen in Training","Assist with dormitory accountability formations","Serve as a positive role model for peers","Report concerns or issues to MTLs","Help maintain dormitory standards"]}]},{"badge":"Yellow Rope","color":"amber","title":"Yellow Rope - Floor Leader","description":"The Yellow Rope is an intermediate leadership position. Yellow Ropes take on additional duties assisting MTLs with day-to-day floor operations and student management.","sections":[{"title":"Requirements","items":["Minimum 30 days as a Green Rope","Demonstrated leadership potential","Maintain 85% or higher academic average","No disciplinary actions as a Green Rope","Recommendation from supervising MTL and current rope leadership"]},{"title":"Responsibilities","items":["Assist MTLs with floor operations and inspections","Lead dormitory details and work parties","Mentor and evaluate Green Ropes","Conduct peer-led training sessions","Manage daily accountability for assigned floor","Coordinate with MTLs on student issues"]}]},{"badge":"Red Rope","color":"red","title":"Red Rope - Senior Student Leader","description":"The Red Rope is the highest student leadership position. Red Ropes serve as the senior student leaders, managing all other rope holders and serving as the primary liaison between students and MTLs.","sections":[{"title":"Requirements","items":["Minimum 30 days as a Yellow Rope","Exceptional leadership record","Maintain 90% or higher academic average","Top fitness scores","Endorsement from multiple MTLs and Group leadership","Interview with senior NCO leadership"]},{"title":"Responsibilities","items":["Serve as primary student liaison to MTL corps","Manage and mentor all Green and Yellow Ropes","Lead major formations and student events","Represent students at leadership meetings","Assist with in-processing of new students","Coordinate special projects with MTLs","Conduct rope holder evaluations"]}]}]},{"type":"highlight-card","icon":"Award","title":"Interested in Becoming a Rope?","description":"Speak with your MTL about eligibility and the application process. Leadership starts with stepping up — your MTL can guide you through the requirements and help you begin your leadership journey.","variant":"navy"}]}'::jsonb, 'Student leadership opportunities through the Rope Program at the 937th Training Group.', 'static',  true,  20),
('Spartan Flight / CQ',             'spartan-flight',      '{"blocks":[{"type":"info-cards","columns":1,"cards":[{"icon":"Shield","color":"blue","title":"About CQ Duty","description":"Charge of Quarters (CQ) is a rotating duty assigned to AiT students to maintain security and accountability in the dormitories during after-duty hours. CQ runners work in shifts alongside the Duty MTL to ensure the safety and well-being of all dormitory residents."}]},{"type":"contact-info","columns":3,"items":[{"icon":"Clock","label":"Shift 1","value":"1800 - 0000","kind":"text"},{"icon":"Clock","label":"Shift 2","value":"0000 - 0600","kind":"text"},{"icon":"Phone","label":"CQ Desk","value":"210-808-3150","kind":"phone"}]},{"type":"checklist","icon":"Shield","color":"blue","title":"CQ Duties","variant":"normal","items":[{"text":"Monitor dormitory entrance and maintain visitor log"},{"text":"Conduct hourly floor checks and accountability"},{"text":"Report emergencies and security incidents to MTL on duty"},{"text":"Ensure quiet hours are maintained (2200-0600)"},{"text":"Monitor fire and safety systems"},{"text":"Assist students with after-hours issues"},{"text":"Maintain CQ log with all notable events"}]},{"type":"checklist","icon":"ClipboardList","color":"amber","title":"What to Bring","variant":"tips","items":[{"text":"Military ID / CAC"},{"text":"Water and authorized snacks"},{"text":"Study materials (academics encouraged during downtime)"},{"text":"Uniform items for next duty day"},{"text":"Phone charger"}]},{"type":"highlight-card","icon":"AlertTriangle","title":"CQ duty is a military requirement","description":"Failure to report for duty or abandoning your post may result in disciplinary action. If you have a conflict, notify your MTL as soon as possible to arrange a swap.","variant":"warning"}]}'::jsonb, 'Charge of Quarters duty information and schedules for AiT students.', 'static',  true,  21),
('SAFEREP',                         'saferep',             '{"blocks":[{"type":"info-cards","columns":1,"cards":[{"icon":"ShieldAlert","color":"red","title":"Safety is Everyone''s Responsibility","description":"The 937th Training Group is committed to maintaining a safe environment for all personnel. If you observe an unsafe condition or experience a safety incident, report it immediately. All reports can be made anonymously."}]},{"type":"contact-info","columns":2,"items":[{"icon":"Phone","label":"Emergency (immediate danger)","value":"911","kind":"phone","emphasize":true},{"icon":"Phone","label":"Safety Office (non-emergency)","value":"210-808-3800","kind":"phone"}]},{"type":"checklist","icon":"ShieldAlert","color":"red","title":"What to Report","variant":"normal","items":[{"text":"Unsafe conditions in dormitories, training facilities, or common areas"},{"text":"Hazardous material spills or exposure"},{"text":"Workplace injuries or near-miss incidents"},{"text":"Vehicle accidents (on or off base)"},{"text":"Faulty or damaged equipment"},{"text":"Fire hazards or electrical issues"},{"text":"Slip, trip, and fall hazards"},{"text":"Any condition that could cause injury or property damage"}]},{"type":"highlight-card","icon":"ShieldAlert","title":"See Something? Say Something.","description":"You will never be penalized for reporting a safety concern in good faith. Your report could prevent an injury or save a life. Report to your MTL, supervisor, or call the Safety Office directly.","variant":"navy"}]}'::jsonb, 'Safety reporting information — if you see something unsafe, report it.',                                 'static',  true,  22),
('JBSA Connect',                    'jbsa-connect',        '{"blocks":[{"type":"info-cards","columns":3,"cards":[{"icon":"Globe","color":"military-blue","title":"JBSA Official Website","description":"Official Joint Base San Antonio website with news, events, and resources","url":"https://www.jbsa.mil"},{"icon":"MapPin","color":"military-blue","title":"JBSA Fort Sam Houston","description":"Fort Sam Houston specific information, maps, and services","url":"https://www.jbsa.mil/About-Us/Fort-Sam-Houston/"},{"icon":"Heart","color":"military-blue","title":"JBSA MWR","description":"Morale, Welfare, and Recreation activities and facilities","url":"https://www.jbsamwr.com"},{"icon":"Home","color":"military-blue","title":"Military & Family Readiness","description":"Programs and services for military members and their families","url":"#"},{"icon":"GraduationCap","color":"military-blue","title":"JBSA Education Center","description":"Educational programs, tuition assistance, and testing services","url":"#"},{"icon":"Shield","color":"military-blue","title":"JBSA Security Forces","description":"Base security, gate hours, and visitor information","url":"#"}]}]}'::jsonb, 'External resources and links for Joint Base San Antonio.', 'static',  true,  23),
